const knex = require('knex');
const knexfile = require('../../knexfile');

// 检查环境变量
const isLocalValidation = process.env.LOCAL_VALIDATION === 'true';
const upstashUrl = process.env.UPSTASH_REDIS_REST_URL;
const upstashToken = process.env.UPSTASH_REDIS_REST_TOKEN;

console.log('🔧 运行模式:', isLocalValidation ? '本地验证模式' : '远程服务模式');

if (isLocalValidation) {
  console.log('🔧 本地验证模式 - 使用本地Docker数据库进行迁移验证');
  console.log('🔧 请确保已运行: docker-compose up -d postgres redis');
} else {
  // 远程模式检查Redis配置
  if (!upstashUrl || !upstashToken || upstashUrl === 'your_upstash_redis_url') {
    console.error('❌ 错误: 未找到有效的 Upstash Redis 环境变量');
    console.error('请设置以下环境变量:');
    console.error('- UPSTASH_REDIS_REST_URL');
    console.error('- UPSTASH_REDIS_REST_TOKEN');
    console.error('或者设置 LOCAL_VALIDATION=true 使用本地验证模式');
    process.exit(1);
  }
}

// 使用 knexfile.js 的配置
const environment = isLocalValidation ? 'development' : (process.env.NODE_ENV || 'production');
const dbConfig = knexfile[environment];

console.log('🔧 数据库配置:', {
  environment,
  client: dbConfig.client,
  host: dbConfig.connection.host,
  database: dbConfig.connection.database,
  user: dbConfig.connection.user,
  ssl: dbConfig.connection.ssl ? '已配置' : '未配置'
});

// 创建 Knex 实例
const db = knex(dbConfig);

// 创建 Redis 实例（本地验证模式使用模拟Redis）
let redis;
if (isLocalValidation) {
  console.log('🔧 本地验证模式 - 使用模拟Redis');
  redis = {
    set: async (key, value) => console.log(`模拟Redis SET: ${key} = ${value}`),
    get: async (key) => console.log(`模拟Redis GET: ${key}`),
    del: async (key) => console.log(`模拟Redis DEL: ${key}`),
    exists: async (key) => console.log(`模拟Redis EXISTS: ${key}`),
    expire: async (key, seconds) => console.log(`模拟Redis EXPIRE: ${key} ${seconds}s`)
  };
} else {
  const { Redis } = require('@upstash/redis');
  redis = new Redis({
    url: upstashUrl,
    token: upstashToken,
  });
}

// 测试数据库连接
async function testDatabaseConnection() {
  try {
    console.log('🔌 测试数据库连接...');
    const result = await db.raw('SELECT 1 as test');
    console.log('✅ 数据库连接成功:', result.rows[0]);
    return true;
  } catch (error) {
    console.error('❌ 数据库连接失败:', error.message);
    if (isLocalValidation) {
      console.error('💡 请确保本地Docker数据库已启动: docker-compose up -d postgres');
    }
    return false;
  }
}

// 测试 Redis 连接
async function testRedisConnection() {
  try {
    if (isLocalValidation) {
      console.log('✅ 本地验证模式 - Redis模拟成功');
      return true;
    }
    
    console.log('🔌 测试 Upstash Redis 连接...');
    await redis.set('test_connection', 'success');
    const result = await redis.get('test_connection');
    console.log('✅ Upstash Redis 连接成功:', result);
    await redis.del('test_connection');
    return true;
  } catch (error) {
    console.error('❌ Redis 连接失败:', error.message);
    return false;
  }
}

// 验证数据库表结构
async function validateDatabaseSchema() {
  try {
    console.log('🔍 验证数据库表结构...');
    
    // 检查是否存在关键表
    const tables = await db.raw(`
      SELECT table_name 
      FROM information_schema.tables 
      WHERE table_schema = 'public'
      ORDER BY table_name
    `);
    
    console.log('📋 当前数据库表:', tables.rows.map(row => row.table_name));
    
    // 检查关键表是否存在
    const requiredTables = ['users', 'patterns', 'pixels', 'sessions'];
    const existingTables = tables.rows.map(row => row.table_name);
    
    const missingTables = requiredTables.filter(table => !existingTables.includes(table));
    
    if (missingTables.length > 0) {
      console.log('⚠️  缺少关键表:', missingTables);
      console.log('💡 建议运行数据库迁移: npm run migrate');
    } else {
      console.log('✅ 所有关键表都存在');
    }
    
    return true;
  } catch (error) {
    console.error('❌ 表结构验证失败:', error.message);
    return false;
  }
}

// 初始化连接测试
async function initializeConnections() {
  const dbConnected = await testDatabaseConnection();
  const redisConnected = await testRedisConnection();
  
  if (dbConnected && redisConnected) {
    console.log('✅ 所有服务连接成功');
    
    if (isLocalValidation) {
      await validateDatabaseSchema();
    }
  } else {
    console.error('❌ 服务连接失败');
    if (isLocalValidation) {
      process.exit(1);
    }
  }
}

// 立即执行连接测试
initializeConnections();

module.exports = {
  db,
  redis
};

console.log('Database config loaded successfully');

